import{_ as a,o as t,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"SFMC Configuration","description":"","frontmatter":{"title":"SFMC Configuration","slug":"sfmc-overview"},"headers":[],"relativePath":"developer-hub/sfmc-overview.md","filePath":"developer-hub/sfmc-overview.md"}'),o={name:"developer-hub/sfmc-overview.md"};function r(l,e,s,c,d,h){return t(),i("div",null,[...e[0]||(e[0]=[n('<p><em>[Image: 1328]</em></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Driving your customers from email to app is an amazing way for them to get more comfortable with your brand and increase conversions. Branch Email and Salesforce Marketing Cloud integrate together to improve user experiences and boost retention rates.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li><p>User clicks on a link in an email from their mobile mail client (Gmail, Apple Mail, etc.)</p></li><li><p>If the user has the app installed and the link has a corresponding screen in the app, the app will open and deep link the user to the right content.</p><ul><li>Ex. Product detail page, category shopping page, etc.</li></ul></li><li><p>If the user does not have the app installed or the link only corresponds to a screen on the web, the user is routed to the website using their default mobile web browser.</p><ul><li>Ex. Unsubscribe link, privacy policy, etc.</li></ul></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Required Roles</p><p>Branch Email requires the following roles involved in order to enable:</p><ul><li>Developers</li><li>CRM/Email Team</li><li>Salesforce Account Manager / Support Team</li></ul></div><p>In order to enable Salesforce Marketing Cloud Web Default, you must first:</p><ol><li><p>Have admin access to your <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Have Branch&#39;s Engagement <a href="./packaging.html">product</a> enabled for your Branch Account.</p></li><li><p>Implement the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><p>Set Up Deep Link Routing. How your mobile app routes to in-app content will determine how you will create and tag your Branch Links.</p><ul><li><a href="./in-app-routing.html#option-1-build-custom-routing-inside-the-routing-callback">Build custom routing inside the routing callback</a></li><li><a href="./in-app-routing.html#option-2-let-branch-use-your-existing-deep-link-routing">Let Branch use your existing deep link routing</a></li></ul></li><li><p><a href="./track-branch-events.html">Track events</a></p></li></ul></li><li><p>Review our <a href="./email-overview.html">Email Overview</a> and <a href="./email-integration-guide.html">Basic Email Integration Guide</a> to understand the feature and our integrations.</p></li><li><p>Obtain or set up your Salesforce Marketing Cloud <strong>click tracking domain</strong> (CTD). Reach out to your Salesforce account manager for assistance on this.</p><ul><li>Only one SAP &amp; CTD is allowed per business unit (BU/MID)</li><li>Ensure that CTD is secure (<code>https://</code>). If not, purchase an SSL SKU through your Salesforce account manager.</li></ul></li></ol><h2 id="enable-salesforce-marketing-cloud" tabindex="-1">Enable Salesforce Marketing Cloud <a class="header-anchor" href="#enable-salesforce-marketing-cloud" aria-label="Permalink to &quot;Enable Salesforce Marketing Cloud&quot;">​</a></h2><h2 id="_1-connect-salesforce-in-branch" tabindex="-1">1. Connect Salesforce in Branch <a class="header-anchor" href="#_1-connect-salesforce-in-branch" aria-label="Permalink to &quot;1. Connect Salesforce in Branch&quot;">​</a></h2><p>In the Branch Dashboard in Email → <a href="https://dashboard.branch.io/email/manager" target="_blank" rel="noreferrer">Manager tab</a>, find <strong>Salesforce Marketing Cloud Ver. 1</strong> and click <strong>Enable</strong></p><p><em>[Image: 385]</em></p><h3 id="input-click-tracking-domain" tabindex="-1">Input Click Tracking Domain <a class="header-anchor" href="#input-click-tracking-domain" aria-label="Permalink to &quot;Input Click Tracking Domain&quot;">​</a></h3><p>Enter your click tracking domain in the open field and click <strong>Save</strong></p><div class="warning custom-block"><p class="custom-block-title">Click Tracking Domain</p><ul><li>Remove <code>https://</code> when adding your click tracking domain.</li><li>Never add the same CTD to both your <strong>Live</strong> and <strong>Test</strong> Branch environments.</li><li>You can enable the integration with multiple CTDs, if needed, but you <strong>cannot</strong> add the same CTD to multiple Branch Dashboards or ESP integrations.</li></ul></div><h2 id="_2-configure-salesforce" tabindex="-1">2. Configure Salesforce <a class="header-anchor" href="#_2-configure-salesforce" aria-label="Permalink to &quot;2. Configure Salesforce&quot;">​</a></h2><p>You must reach out to your Salesforce account manager to enable <strong>web-only default tagging</strong> for</p><div class="info custom-block"><p class="custom-block-title">Enable Web-Only Default Tagging</p><p>Reach out to your Salesforce account manager to enable <strong>Web-Only Default Tagging</strong> for your Salesforce BU by providing your Salesforce account MID(s).</p><p>Once enabled, all emails sent from those MIDs will click wrap every link with a click tracking domain using a <code>/u</code> path, which prevents the app from opening in iOS <em>(Emails that have already been sent before enabling will open the app because they will not have</em> <code>/u</code> <em>in the path)</em>.</p><p>If you run <strong>Journey Builder or Triggered Sends</strong>, you must do one of the following to ensure the web-only tagging is applied to those emails:</p><ul><li>Republish the journey triggered sends via Email Studio Triggered Send dashboard</li><li>Update the email activities in Journey Builder</li><li>Create a new journey version</li></ul></div><h3 id="configure-aasa-file-in-salesforce-marketing-cloud" tabindex="-1">Configure AASA File in Salesforce Marketing Cloud <a class="header-anchor" href="#configure-aasa-file-in-salesforce-marketing-cloud" aria-label="Permalink to &quot;Configure AASA File in Salesforce Marketing Cloud&quot;">​</a></h3><p>Your Salesforce account must be configured to correctly handle Universal Links. Configure the settings in Deep Linking under the Send Management section in Email Studio. Ensure you&#39;re in the account corresponding to the correct click tracking domain.</p><ol><li>Enter the AppID value</li><li>Check the &quot;Exclude Profile&quot; and &quot;Unsub Center&quot; checkboxes to force links to these items to open in the browser and not the app, if desired.</li><li>Click &quot;Save&quot; to save the configuration.</li><li>Let Salesforce and Branch know that you&#39;ve finished this step and your Technical Account Manager will verify that everything looks good.</li></ol><p>Note: AppID = prefix+bundleID</p><h2 id="_3-configure-your-app" tabindex="-1">3. Configure your App <a class="header-anchor" href="#_3-configure-your-app" aria-label="Permalink to &quot;3. Configure your App&quot;">​</a></h2><h3 id="add-your-salesforce-ctd-to-your-associated-domains" tabindex="-1">Add your Salesforce CTD to your Associated Domains <a class="header-anchor" href="#add-your-salesforce-ctd-to-your-associated-domains" aria-label="Permalink to &quot;Add your Salesforce CTD to your Associated Domains&quot;">​</a></h3><p>For your iOS App, you must add the CTD to the Associated Domains. Additional details can be found <a href="./ios-basic-integration.html#3-configure-associated-domains">here</a>.</p><p>.png &quot;Associated Domains.png&quot;)</p><p>If you do not have your CTD, reach out to your Salesforce Marketing Cloud account manager.</p><h3 id="return-yes-to-continueuseractivity" tabindex="-1">Return <code>YES</code> to <code>continueUserActivity</code> <a class="header-anchor" href="#return-yes-to-continueuseractivity" aria-label="Permalink to &quot;Return `YES` to `continueUserActivity`&quot;">​</a></h3><p>Additionally, you will need to add the CTD to your iOS app&#39;s info.plist file. Additional details can be found <a href="./ios-advanced-features.html#return-yes-to-continueuseractivity">here</a>.</p><p>.png &quot;branch-universal-link-domain.png&quot;)</p><div class="info custom-block"><p class="custom-block-title">Custom Link Domain</p><p>If you are using a custom link domain and AMPscript to generate Branch Links (more on this on the next step), include your original app.link domain in both Associated Domains and info.plist <strong>and</strong> use the app.link domain as the base Branch URL in AMPscript</p></div><h2 id="_4-add-branch-links-to-your-emails" tabindex="-1">4. Add Branch Links to your Emails <a class="header-anchor" href="#_4-add-branch-links-to-your-emails" aria-label="Permalink to &quot;4. Add Branch Links to your Emails&quot;">​</a></h2><h3 id="add-deep-linking-flag" tabindex="-1">Add Deep Linking Flag <a class="header-anchor" href="#add-deep-linking-flag" aria-label="Permalink to &quot;Add Deep Linking Flag&quot;">​</a></h3><p>For the links in your email that you want to your customers to deep link into app content, you must add the <code>mc-deep-link=&quot;true&quot;</code> flag to the links.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;a &quot;mc-deep-link=&quot;true&quot; href=&quot;https://branch.app.link/...&gt; click me! &lt;/a&gt;</span></span></code></pre></div><h3 id="add-branch-links" tabindex="-1">Add Branch Links <a class="header-anchor" href="#add-branch-links" aria-label="Permalink to &quot;Add Branch Links&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">Advanced AMPscript</p><p>If your workflow utilizes AMPscript for your email sends, you can configure AMPscript to generate your Branch Links. Follow the AMPscript guide <a href="./ampscript-for-salesforce-marketing-cloud.html">here</a>.</p></div><h4 id="short-links" tabindex="-1">Short Links <a class="header-anchor" href="#short-links" aria-label="Permalink to &quot;Short Links&quot;">​</a></h4><p>Use Branch <a href="./create-quick-links.html">Short Links</a> to create your Branch Link to be placed in your email template.</p><h5 id="name-your-link" tabindex="-1">Name your Link <a class="header-anchor" href="#name-your-link" aria-label="Permalink to &quot;Name your Link&quot;">​</a></h5><p>Add your original URL (ex. link to your product) to the <strong>Original Web URL</strong> field.</p><h5 id="analytics-tags" tabindex="-1">Analytics Tags <a class="header-anchor" href="#analytics-tags" aria-label="Permalink to &quot;Analytics Tags&quot;">​</a></h5><table tabindex="0"><thead><tr><th>Analytics Tag</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td>Feature</td><td>Feature should describe the action or product where this link is placed. In the UTM world, this is typically utm_medium.</td><td>Salesforce Marketing Cloud</td></tr><tr><td>Channel</td><td>Channel should describe the platform or source from which you are expecting users to click this link. In the UTM world, this is typically utm_source.</td><td>Email</td></tr><tr><td>Campaign</td><td>Campaign varies from company to company, but it should describe the theme of the link. In the UTM world, this is typically utm_campaign.</td><td>Transactional - Add Item</td></tr><tr><td>Tags</td><td>Tags are a free-form list of meaningful labels that can be used as filters in the Short Links table. Use them to keep your analytics organized.</td><td>September Sale</td></tr></tbody></table><h5 id="link-data" tabindex="-1">Link Data <a class="header-anchor" href="#link-data" aria-label="Permalink to &quot;Link Data&quot;">​</a></h5><table tabindex="0"><thead><tr><th>Key</th><th>Description</th><th>Value</th></tr></thead><tbody><tr><td><code>$3p</code></td><td>This is the indicator for a specific partner of Branch. It is set in order for Branch&#39;s systems to properly attribution conversions</td><td><code>e_et</code></td></tr><tr><td><code>$canonical_url</code></td><td>The canonical URL, served for SEO purposes.</td><td>{Automatically from the <strong>Original Web URL</strong>.}</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Link Templates</p><p>You can utilize Branch&#39;s <strong>Link Templates</strong> feature in order to make Short Link creation much faster for your workflow 👌. Learn more <a href="./link-templates.html">here</a>.</p></div><p>Once you generate your Short Link, you can then place that link into your email template. Your email template should have links like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;a mc-deep-link=&quot;true&quot; href=&quot;https://my.app.link/abc123&quot; &gt; Open App &lt;/a&gt;</span></span></code></pre></div><h2 id="advanced" tabindex="-1">Advanced <a class="header-anchor" href="#advanced" aria-label="Permalink to &quot;Advanced&quot;">​</a></h2><h3 id="track-web-links" tabindex="-1">Track Web Links <a class="header-anchor" href="#track-web-links" aria-label="Permalink to &quot;Track Web Links&quot;">​</a></h3><p>By default, this integration will not let you track web link. Enabling web tracking on specific links will open the web -- not the app.</p><details><summary>Method 1: Modified Branch Short Link</summary><ol><li><p>In the Branch Dashboard, create a <a href="https://branch.dashboard.branch.io/quick-links" target="_blank" rel="noreferrer">Short Link</a>.</p></li><li><p>Add campaign tag for tracking.</p></li><li><p>In the Deep Linking tab, add <strong>has_app = false</strong> and <strong>$web_only = true</strong> to the link data.</p></li><li><p>In the Redirects tab, set the web redirects for fallbacks. Select web URL for Android, iOS, and Desktop, and add the URL you want to redirect to.</p></li><li><p>After the link is created, add <code>_webonly</code> to the app.link domain.<br> * Ex: If the link created is <a href="https://branchster.app.link/weblinktest" target="_blank" rel="noreferrer">https://branchster.app.link/weblinktest</a>, convert it to <a href="https://branchster_webonly.app.link/weblinktestt" target="_blank" rel="noreferrer">https://branchster_webonly.app.link/weblinktest</a>.</p></li></ol></details><details><summary>Method 2: Branch Long Link</summary><ul><li><p>Start with your app.link domain, and add <code>_webonly</code> to it.</p><ul><li>Ex: If your app.link domain is <a href="https://branchster.app.link" target="_blank" rel="noreferrer">https://branchster.app.link</a>, convert it to <a href="https://branchster_webonly.app.link" target="_blank" rel="noreferrer">https://branchster_webonly.app.link</a></li></ul></li><li><p>Add <strong>has_app = false</strong> and <strong>$web_only=true</strong> as query parameters.</p><ul><li>Ex: <a href="https://branchster_webonly.app.link?has_app=false&amp;$web_only=true" target="_blank" rel="noreferrer">https://branchster_webonly.app.link?has_app=false&amp;$web_only=true</a></li></ul></li><li><p>Add <strong>~campaign</strong> tag to the link.</p><ul><li>Ex: (<a href="https://branchster_webonly.app.link/?has_app=false&amp;$web_only=true&amp;~campaign=email-test-cam" target="_blank" rel="noreferrer">https://branchster_webonly.app.link/?has_app=false&amp;$web_only=true&amp;~campaign=email-test-cam)[https://branchster_webonly.app.link/?has_app=false&amp;$web_only=true&amp;~campaign=email-test-cam]</a>%5Bhttps://branchster_webonly.app.link/?has_app=false&amp;$web_only=true&amp;~campaign=email-test-cam%5D)</li></ul></li><li><p>Add the URI encoded web redirect link as <strong>$fallback_url</strong>.</p><ul><li>Ex: (<a href="https://branchster_webonly.app.link/?has_app=false&amp;$web_only=true&amp;~campaign=email-test-cam&amp;$fallback_url=https%3A%2F%2Fwww.myweblink.com%2F" target="_blank" rel="noreferrer">https://branchster_webonly.app.link/?has_app=false&amp;$web_only=true&amp;~campaign=email-test-cam&amp;$fallback_url=https%3A%2F%2Fwww.myweblink.com%2F)[https://branchster_webonly.app.link/?has_app=false&amp;$web_only=true&amp;~campaign=email-test-cam&amp;$fallback_url=https%3A%2F%2Fwww.myweblink.com%2F]</a>%5Bhttps://branchster_webonly.app.link/?has_app=false&amp;$web_only=true&amp;~campaign=email-test-cam&amp;$fallback_url=https%3A%2F%2Fwww.myweblink.com%2F%5D)</li></ul></li></ul></details><p><strong>Analytics on the Branch Dashboard</strong></p><p>To see how the email campaigns have performed and break it down into campaigns, it is very essential to tag those links with the ~campaign tag. This will help dedupe the numbers and hence see the downstream events. You can add the campaign tag in any comparisons and filters in any Dashboard views.</p>',56)])])}const m=a(o,[["render",r]]);export{u as __pageData,m as default};
